+    pub fn edge_count(&self) -> usize {
+        self.nodes.values().map(|n| n.inputs.len()).sum()
+    }
+
+    /// Whether the graph has no dirty nodes pending propagation.
+    #[must_use]
+    pub fn is_stable(&self) -> bool {
+        self.dirty.is_empty()
+    }
